scwin.onpageload = async function() {
    console.log("====== onpageload ==================v 1.01");

     const codeOptions1 = [
		{ grpCd : "ZZ006", compID : "lc_crcCd , gr_total:crcCd"} //<%= GauceUtil.getCodeList("SD113", new int[] {1,3}, new String[] {DsConstants.ODR_CNTR, "1" }) %>">
	];

    await $c.data.setCommonCode(codeOptions1);
};

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    console.log("  ==--== onUdcCompleted");

    // 2025-10-14 : 작성일자 포커스 위치 이동
    $p.setTimeout(function () {
        scwin.f_Setting();
	    scwin.f_setCompanyInfo();

        // paging 처리 관련
        $c.gus.cfDisableObjects([btn_addSearch]);
        btn_addSearch.hide();
	    bSearch.hide();
	    lAddRow.hide();
	    bSearch2.hide();

        scwin.getQuantityOfRows();
	}, { "delay": 50 });
};


