//-------------------------------------------------------------------------
// 기본셋팅
//------------------------------------------------------------------------- 
scwin.f_Setting = function(){

    scwin.memJson = $c.data.getMemInfo();

    scwin.vLoginCoCd =$c.gus.cfIsNull(scwin.memJson.getCoCd)?'':scwin.memJson.getCoCd; // 소속 자회사  
    scwin.vLoginCoClsCd =$c.gus.cfIsNull(scwin.memJson.getCoClsCd)?'': scwin.memJson.getCoClsCd  ;//회계_회사구분('CO035' : 0:동부 EXPRESS)
    scwin.vUserHomeClsCd= scwin.memJson.getUserHomeClsCd;        // 사용자소속구분코드 
    scwin.isSubCompany = false;
    scwin.vCoCd =$c.gus.cfIsNull(scwin.memJson.getCoCd)?'':scwin.memJson.getCoCd; // 소속 자회사  
    scwin.vCoClsCd =$c.gus.cfIsNull(scwin.memJson.getCoClsCd)?'': scwin.memJson.getCoClsCd;//회계_회사구분('CO035' : 0:동부 EXPRESS

    scwin.strDate = WebSquare.date.getCurrentServerDate().substring(0, 6);
    scwin.strCurDate = WebSquare.date.getCurrentServerDate().substring(0, 8);
    scwin.privAdmin  =  scwin.memJson.getPrivAdmin;// ADMIN 권한 CHK : 'T' : ADMIN , 'F': ADMIN 아님
    ds_search.set("qryYm", scwin.strDate)
    ds_search.set("qryYmEnd", scwin.strDate);

    ed_acctCdSt.options.hidVal = ds_search.get("acctCdSt");
    ed_acctDeptCd.options.hidVal = ds_search.get("acctDeptCd");

	ed_qryYm.focus();
};

//-------------------------------------------------------------------------
// 자회사 회계 시스템 추가에 따른 설정 
//-------------------------------------------------------------------------
scwin.f_setCompanyInfo = function(){   
    // 사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를  '동부 EXPRESS'로  Default set
    if( scwin.vUserHomeClsCd != ACConstants.SUBSIDIARY_USER_HOME_CLS_CD)  {  
        scwin.vLoginCoCd = ACConstants.CO_CD_DONGBU;
        scwin.vLoginCoClsCd = ACConstants.CO_CLS_CD_DONGBU ;
    }

    ed_coCd.setValue(scwin.vLoginCoCd);
    scwin.f_PopUpCompanyInfo('T'); 

    if('T' == scwin.privAdmin  ||  !scwin.isSubCompany   ) { // ADMIN 권한이 있는 경우, 동부 EXPRESS 인 경우 
        $c.gus.cfEnableObjects([ed_coCd, ed_coNm, btn_coCd ]);    
    }else {
        $c.gus.cfDisableObjects([ed_coCd,scwin.txt_coNm, btn_coCd  ]);   
    }  
};

//-------------------------------------------------------------------------
// FI616 (조회데이터Row설정) 조회
//-------------------------------------------------------------------------
scwin.getQuantityOfRows = function(){
    console.log("===== getQuantityOfRows - FI616 (조회데이터Row설정) 조회");

    let grp_cd ="FI616";  // 조회데이터Row설정 - 1000

    // SELECT 절 
    let param1 = 
            " CD      as COL1 "
        + ",CD_NM 	as COL2 "
        + ",'' 		as COL3 "
        + ",'' 		as COL4 "
        + ",'' 		as COL5 "
        + ",'' 		as COL6 "
        + ",''      as COL7 "
        + ",''      as COL8 "
        + ",''      as COL9 "
        + ",''      as COL10"
        ;

    // 대상테이블 	
    let param2 = 			
            " TB_ZZ002 "
        ;

    // 조건절
    let param3 = 
            " AND GRP_CD = '"+grp_cd+"'" 
        + " AND CD = '01' "
        + " AND USE_YN = '1' "
        ;

    // 정렬    
    let param4 = 	
            " CD "
        ;

    // ds_test.DataId = 
    // "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC&queryId=dinymicQueryTest" + "&param1=" + param1 
    //                                                                             + "&param2=" + param2
    //                                                                             + "&param3=" + param3 
    //                                                                             + "&param4=" + param4;	                                                    
    // ds_test.Reset();  		

    sbm_test.action = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC&queryId=dinymicQueryTest" + "&param1=" + param1 + "&param2=" + param2 + "&param3=" + param3 + "&param4=" + param4;
    $c.sbm.execute(sbm_test);
};

scwin.sbm_test_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code != 0) {
        return;
    }
    // console.log("  FI616 (조회데이터Row설정) 건수 ["+ds_test.getTotalRow()+"]");
};


