//-------------------------------------------------------------------------
// 전표내역/증빙내역 팝업
//-------------------------------------------------------------------------
scwin.gr_total_oncellclick = function (rowIndex, columnIndex, columnId) {
    if(ds_total.getCellData(rowIndex,"slipNo") != '')
	{
		if(columnId=="slipNo" && ds_total.getRowCount() >0){
			scwin.f_evidPopUp2();
		}
	}

	if(columnId =="evidenceCnt" && ds_total.getRowCount() >0){
		scwin.f_evidPopUp();
	}
};


